import React from 'react';
import DashboardLayout from './components/DashboardLayout';

/**
 * Main App component
 */
function App() {
  return (
    <DashboardLayout>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {/* Placeholder for data cards */}
        <div className="bg-gray-800 p-4 rounded shadow">
          <h3 className="text-lg font-semibold">Total Users</h3>
          <p className="text-2xl">150</p>
        </div>
        <div className="bg-gray-800 p-4 rounded shadow">
          <h3 className="text-lg font-semibold">Active Projects</h3>
          <p className="text-2xl">12</p>
        </div>
        <div className="bg-gray-800 p-4 rounded shadow">
          <h3 className="text-lg font-semibold">Revenue</h3>
          <p className="text-2xl">$50K</p>
        </div>
        <div className="bg-gray-800 p-4 rounded shadow">
          <h3 className="text-lg font-semibold">System Health</h3>
          <p className="text-2xl">98%</p>
        </div>
      </div>
      {/* Placeholder for charts and other components */}
      <div className="bg-gray-800 p-4 rounded shadow">
        <h3 className="text-lg font-semibold mb-4">Charts and Data Table</h3>
        <p>Interactive charts and CRUD table will be added here.</p>
      </div>
    </DashboardLayout>
  );
}

export default App;
